28	const basePremiumFor = (type: string): number => BASE_PREMIUM[type] ?? 0;
29	
30	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
31	
32	const isMainItem = (item: Item): boolean => !isComponent(item);
33	
34	const groupByType = (items: Item[]): Map<string, number> =>
35	  items.reduce((counts, { type }) => counts.set(type, (counts.get(type) ?? 0) + 1), new Map<string, number>());
36	
37	const componentGroupPremium = (type: string, count: number): number =>
38	  count === BLOCK_OF_THREE_SIZE ? BLOCK_OF_THREE_PREMIUM : count * basePremiumFor(type);
39	
40	const componentsPremium = (items: Item[]): number =>
41	  Array.from(groupByType(items.filter(isComponent)))
42	    .reduce((sum, [type, count]) => sum + componentGroupPremium(type, count), 0);
43	
44	const isHighlyEnchanted = (item: Item): boolean =>
45	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
46	
47	const rateWhen = (applies: boolean, rate: number): number => (applies ? rate : 0);
48	
49	const applyRate = (base: number, rate: number): number => base * (1 + rate);
50	
51	const itemRateAdjustment = (item: Item): number =>
52	  rateWhen(item.cursed === true, CURSED_SURCHARGE) +
53	  rateWhen(isHighlyEnchanted(item), HIGH_ENCHANTMENT_SURCHARGE);
54	
55	const itemPremium = (item: Item): number =>
56	  applyRate(basePremiumFor(item.type), itemRateAdjustment(item));
57	
58	const mainItemsPremium = (items: Item[]): number =>
59	  items.filter(isMainItem)
60	    .reduce((sum, item) => sum + itemPremium(item), 0);
61	
