63	  items.filter(isMainItem)
64	    .reduce((sum, item) => sum + basePremiumFor(item.type), 0);
65	
66	const itemsPremium = (items: Item[]): number =>
67	  mainItemsPremium(items) + componentsPremium(items);
68	
69	const policyBasePremium = (items: Item[]): number =>
70	  mainItemsBasePremium(items) + componentsPremium(items);
71	
72	const isLongStanding = (customer: Customer): boolean =>
73	  (customer.yearsWithMHPCO ?? 0) >= LOYALTY_YEARS_THRESHOLD;
74	
